import React from 'react';

const SiteCard = ({ site, onEdit, onDelete }) => {
  const statusMap = {
    online: { cls: 'badge-online', label: 'Online', icon: '🟢' },
    offline: { cls: 'badge-offline', label: 'Offline', icon: '🔴' },
    unknown: { cls: 'badge-unknown', label: 'Checking', icon: '🟡' },
  };

  const status = statusMap[site.status] || statusMap.unknown;

  const formatDate = (date) => {
    if (!date) return 'Never';
    return new Date(date).toLocaleString('en-US', {
      month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  };

  return (
    <div className="site-card">
      <div className="site-favicon">🌐</div>
      <div className="site-info">
        <div className="site-name">{site.name || site.domain}</div>
        <div className="site-domain">{site.domain}</div>
        <div style={{ marginTop: '4px', fontSize: '11px', color: 'var(--text-muted)' }}>
          Checked: {formatDate(site.last_checked)}
        </div>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flexShrink: 0 }}>
        <span className={`badge-status ${status.cls}`}>
          <span className="pulse"></span>
          {status.label}
        </span>
        <button
          className="btn-ghost"
          onClick={() => onEdit(site)}
          title="Edit"
          style={{ padding: '7px 12px' }}
        >
          <i className="bi bi-pencil"></i>
        </button>
        <button
          className="btn-danger-hm"
          onClick={() => onDelete(site)}
          title="Delete"
        >
          <i className="bi bi-trash"></i>
        </button>
      </div>
    </div>
  );
};

export default SiteCard;
